import React, { useState, useEffect, useRef } from 'react';
import { getSaleReport, getItemWiseReport, getInternalSaleReport, getInternalMasters } from '../services/api';

const fmt = n => `₹${parseFloat(n || 0).toFixed(2)}`;
const payColor = { cash: 'badge-green', card: 'badge-blue', upi: 'badge-purple', cash_card: 'badge-yellow', cash_upi: 'badge-yellow' };
const payLabel = { cash: '💵 Cash', card: '💳 Card', upi: '📱 UPI', cash_card: 'Cash & Card', cash_upi: 'Cash & UPI' };

// ─────────────────────────────────────────────────────────────────────────────
// Print Date Range Modal
// ─────────────────────────────────────────────────────────────────────────────
function PrintModal({ onClose, onPrint }) {
  const today = new Date().toISOString().split('T')[0];
  const [from, setFrom] = useState(today);
  const [to,   setTo]   = useState(today);
  const [loading, setLoading] = useState(false);

  const handlePrint = async () => {
    if (!from || !to) { return; }
    if (from > to) { alert('From date cannot be after To date'); return; }
    setLoading(true);
    await onPrint(from, to);
    setLoading(false);
  };

  return (
    <div className="modal-overlay">
      <div className="modal" style={{ maxWidth: 380 }}>
        <h2>🖨️ Print Sale Report</h2>
        <p style={{ color: 'var(--text3)', fontSize: 13, marginBottom: 20 }}>
          Select the date range for the report.
        </p>
        <div className="form-row">
          <div className="form-group" style={{ margin: 0 }}>
            <label>From Date</label>
            <input type="date" value={from} onChange={e => setFrom(e.target.value)} />
          </div>
          <div className="form-group" style={{ margin: 0 }}>
            <label>To Date</label>
            <input type="date" value={to} onChange={e => setTo(e.target.value)} />
          </div>
        </div>
        <div style={{ display: 'flex', gap: 10, marginTop: 20 }}>
          <button className="btn btn-primary" style={{ flex: 1, justifyContent: 'center' }}
            onClick={handlePrint} disabled={loading}>
            {loading ? 'Preparing…' : '🖨️ Print'}
          </button>
          <button className="btn btn-secondary" onClick={onClose}>Cancel</button>
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Printable Sale Report — rendered off-screen, then window.print() is called
// ─────────────────────────────────────────────────────────────────────────────
function PrintableSaleReport({ data, from, to }) {
  const { bills, totals } = data;

  return (
    <div style={{ fontFamily: 'monospace', fontSize: 13, color: '#000', background: '#fff', padding: 32, minWidth: 600 }}>
      {/* Header */}
      <div style={{ textAlign: 'center', marginBottom: 24 }}>
        <div style={{ fontSize: 22, fontWeight: 800 }}>🧁 BAKESALE</div>
        <div style={{ fontSize: 13, marginTop: 4 }}>Sale Report</div>
        <div style={{ fontSize: 12, marginTop: 4, color: '#555' }}>
          Period: {from} to {to}
        </div>
        <div style={{ fontSize: 11, color: '#888', marginTop: 2 }}>
          Printed on: {new Date().toLocaleString()}
        </div>
      </div>

      {/* Summary totals */}
      <div style={{ border: '1px solid #ccc', borderRadius: 6, padding: '12px 16px', marginBottom: 24, background: '#f9f9f9' }}>
        <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 10, borderBottom: '1px solid #ddd', paddingBottom: 6 }}>
          Payment Summary
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '6px 32px' }}>
          {[
            { label: 'Cash Total',  value: fmt(totals.cash_total) },
            { label: 'Card Total',  value: fmt(totals.card_total) },
            { label: 'UPI Total',   value: fmt(totals.upi_total) },
          ].map(r => (
            <div key={r.label} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13 }}>
              <span style={{ color: '#555' }}>{r.label}</span>
              <span style={{ fontWeight: 600 }}>{r.value}</span>
            </div>
          ))}
        </div>
        <div style={{ borderTop: '2px solid #333', marginTop: 10, paddingTop: 8, display: 'flex', justifyContent: 'space-between', fontSize: 15, fontWeight: 800 }}>
          <span>Grand Total</span>
          <span>{fmt(totals.grand_total)}</span>
        </div>
      </div>

      {/* Bill details table */}
      <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12 }}>
        <thead>
          <tr style={{ background: '#f0f0f0' }}>
            <th style={{ border: '1px solid #ccc', padding: '7px 10px', textAlign: 'left' }}>Bill No</th>
            <th style={{ border: '1px solid #ccc', padding: '7px 10px', textAlign: 'left' }}>Date & Time</th>
            <th style={{ border: '1px solid #ccc', padding: '7px 10px', textAlign: 'left' }}>Payment Type</th>
            <th style={{ border: '1px solid #ccc', padding: '7px 10px', textAlign: 'right' }}>Total Amount</th>
          </tr>
        </thead>
        <tbody>
          {bills.map((b, i) => (
            <tr key={b.id} style={{ background: i % 2 === 0 ? '#fff' : '#fafafa' }}>
              <td style={{ border: '1px solid #ccc', padding: '6px 10px', fontWeight: 600 }}>{b.bill_number}</td>
              <td style={{ border: '1px solid #ccc', padding: '6px 10px', color: '#555' }}>{new Date(b.created_at).toLocaleString()}</td>
              <td style={{ border: '1px solid #ccc', padding: '6px 10px' }}>{payLabel[b.payment_type] || b.payment_type}</td>
              <td style={{ border: '1px solid #ccc', padding: '6px 10px', textAlign: 'right', fontWeight: 600 }}>{fmt(b.total_amount)}</td>
            </tr>
          ))}
        </tbody>
        <tfoot>
          <tr style={{ background: '#f0f0f0', fontWeight: 800 }}>
            <td colSpan={3} style={{ border: '1px solid #ccc', padding: '7px 10px' }}>Grand Total ({bills.length} bills)</td>
            <td style={{ border: '1px solid #ccc', padding: '7px 10px', textAlign: 'right' }}>{fmt(totals.grand_total)}</td>
          </tr>
        </tfoot>
      </table>

      <div style={{ textAlign: 'center', marginTop: 24, fontSize: 11, color: '#999' }}>
        — End of Report —
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Main Reports Page
// ─────────────────────────────────────────────────────────────────────────────
export default function Reports() {
  const [tab,      setTab]      = useState('sale');
  const [itemData, setItemData] = useState([]);
  const [intData,  setIntData]  = useState([]);
  const [masters,  setMasters]  = useState([]);
  const [selDests, setSelDests] = useState([]);
  const [loading,  setLoading]  = useState(false);
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo,   setDateTo]   = useState('');

  // Print state
  const [showPrintModal, setShowPrintModal] = useState(false);
  const [printData,      setPrintData]      = useState(null);  // {data, from, to}
  const printRef = useRef();

  useEffect(() => {
    getInternalMasters().then(r => setMasters(r.data));
  }, []);

  const fetchReport = async () => {
    setLoading(true);
    const params = {};
    if (dateFrom) params.date_from = dateFrom;
    if (dateTo)   params.date_to   = dateTo;
    try {
      if (tab === 'itemwise') {
        const { data } = await getItemWiseReport(params);
        setItemData(data);
      } else if (tab === 'internal') {
        if (selDests.length > 0) params.destinations = selDests.join(',');
        const { data } = await getInternalSaleReport(params);
        setIntData(data);
      }
      // Sale tab has no auto-fetch — data loads only on print
    } catch {}
    setLoading(false);
  };

  useEffect(() => { fetchReport(); }, [tab]);

  const toggleDest = id =>
    setSelDests(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

  // Called from PrintModal — fetches data for the selected range then triggers print
  const handlePrint = async (from, to) => {
    try {
      const { data } = await getSaleReport({ date_from: from, date_to: to });
      setPrintData({ data, from, to });
      setShowPrintModal(false);
      // Give React time to render the hidden print area, then print
      setTimeout(() => window.print(), 300);
    } catch {
      alert('Failed to load report data');
    }
  };

  // Internal report helpers
  const intByDest     = intData.reduce((acc, row) => {
    const key = row.destination_name;
    if (!acc[key]) acc[key] = { items: [], total: 0 };
    acc[key].items.push(row);
    acc[key].total += row.total_amount;
    return acc;
  }, {});
  const intGrandTotal = intData.reduce((s, r) => s + r.total_amount, 0);
  const intTotalQty   = intData.reduce((s, r) => s + r.quantity,     0);

  return (
    <div>
      {/* Hidden printable area — shown only when printing */}
      {printData && (
        <div ref={printRef} className="print-only" style={{ display: 'none' }}>
          <PrintableSaleReport
            data={printData.data}
            from={printData.from}
            to={printData.to}
          />
        </div>
      )}

      <div className="page-header">
        <h1>📊 Reports</h1>
        <div style={{ display: 'flex', gap: 8 }}>
          {/* Date filter — shown for itemwise and internal tabs */}
          {tab !== 'sale' && (
            <>
              <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} style={{ width: 160 }} />
              <input type="date" value={dateTo}   onChange={e => setDateTo(e.target.value)}   style={{ width: 160 }} />
              <button className="btn btn-primary" onClick={fetchReport}>Filter</button>
            </>
          )}
          {/* Print button — only on sale tab */}
          {tab === 'sale' && (
            <button className="btn btn-primary" onClick={() => setShowPrintModal(true)}>
              🖨️ Print Report
            </button>
          )}
        </div>
      </div>

      {/* Tab buttons */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
        {[
          { k: 'sale',     label: '🧾 Sale Report' },
          { k: 'itemwise', label: '📦 Item-wise Report' },
          { k: 'internal', label: '🏭 Internal Sale Report' },
        ].map(t => (
          <button key={t.k} onClick={() => setTab(t.k)} className="btn" style={{
            background: tab === t.k ? 'var(--accent)' : 'var(--surface)',
            color:      tab === t.k ? '#fff'          : 'var(--text2)',
            border:    `1px solid ${tab === t.k ? 'var(--accent)' : 'var(--border)'}`,
            fontSize: 14, fontWeight: 600,
          }}>{t.label}</button>
        ))}
      </div>

      {loading ? <div className="spinner" /> : (
        <>
          {/* ── Sale Report — just a prompt to use Print ── */}
          {tab === 'sale' && (
            <div style={{
              display: 'flex', flexDirection: 'column', alignItems: 'center',
              justifyContent: 'center', padding: '60px 20px',
              background: 'var(--surface)', border: '1px solid var(--border)',
              borderRadius: 'var(--radius-lg)', gap: 16
            }}>
              <div style={{ fontSize: 48 }}>🖨️</div>
              <div style={{ fontWeight: 700, fontSize: 18 }}>Print Sale Report</div>
              <div style={{ color: 'var(--text3)', fontSize: 14, textAlign: 'center', maxWidth: 340 }}>
                Click the button below to select a date range and print the sale report with bill details and payment totals.
              </div>
              <button className="btn btn-primary" style={{ padding: '12px 32px', fontSize: 15 }}
                onClick={() => setShowPrintModal(true)}>
                🖨️ Select Date Range & Print
              </button>
            </div>
          )}

          {/* ── Item-wise Report ── */}
          {tab === 'itemwise' && (
            <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
              <table>
                <thead>
                  <tr><th>Product</th><th>Barcode</th><th>MRP</th><th>Qty Sold</th><th>Total Revenue</th></tr>
                </thead>
                <tbody>
                  {itemData.map((item, i) => (
                    <tr key={i}>
                      <td style={{ fontWeight: 600, color: 'var(--text)' }}>{item.product_name}</td>
                      <td><span style={{ fontFamily: 'var(--mono)', fontSize: 12 }}>{item.product_barcode}</span></td>
                      <td style={{ fontFamily: 'var(--mono)' }}>{fmt(item.mrp)}</td>
                      <td><span className="badge badge-blue">{item.quantity_sold}</span></td>
                      <td style={{ fontWeight: 700, color: 'var(--accent)', fontFamily: 'var(--mono)' }}>{fmt(item.total_amount)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {itemData.length === 0 && (
                <div className="empty-state"><div className="icon">📦</div>No item data in this period</div>
              )}
            </div>
          )}

          {/* ── Internal Sale Report ── */}
          {tab === 'internal' && (
            <>
              {masters.length > 0 && (
                <div style={{ background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: 'var(--radius)', padding: '14px 16px', marginBottom: 16 }}>
                  <div style={{ fontSize: 12, fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--text3)', marginBottom: 10 }}>
                    Filter by Destination
                  </div>
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                    <button onClick={() => setSelDests([])} className="btn btn-sm" style={{
                      background: selDests.length === 0 ? 'var(--accent-dim)' : 'var(--bg3)',
                      color:      selDests.length === 0 ? 'var(--accent)'     : 'var(--text2)',
                      border:    `1px solid ${selDests.length === 0 ? 'var(--accent)' : 'var(--border)'}`,
                    }}>All</button>
                    {masters.map(m => (
                      <button key={m.id} onClick={() => toggleDest(m.id)} className="btn btn-sm" style={{
                        background: selDests.includes(m.id) ? 'var(--accent-dim)' : 'var(--bg3)',
                        color:      selDests.includes(m.id) ? 'var(--accent)'     : 'var(--text2)',
                        border:    `1px solid ${selDests.includes(m.id) ? 'var(--accent)' : 'var(--border)'}`,
                      }}>{m.name}</button>
                    ))}
                    <button className="btn btn-primary btn-sm" onClick={fetchReport} style={{ marginLeft: 'auto' }}>
                      Apply Filter
                    </button>
                  </div>
                </div>
              )}

              {intData.length > 0 && (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 16, marginBottom: 20 }}>
                  <div className="stat-card">
                    <div className="label">Total Items Transferred</div>
                    <div className="value" style={{ color: 'var(--purple)', fontSize: 22 }}>{intTotalQty}</div>
                  </div>
                  <div className="stat-card">
                    <div className="label">Destinations Used</div>
                    <div className="value" style={{ color: 'var(--blue)', fontSize: 22 }}>{Object.keys(intByDest).length}</div>
                  </div>
                  <div className="stat-card">
                    <div className="label">Total Value Transferred</div>
                    <div className="value" style={{ color: 'var(--accent)', fontSize: 22 }}>{fmt(intGrandTotal)}</div>
                  </div>
                </div>
              )}

              {Object.keys(intByDest).length === 0 ? (
                <div className="empty-state"><div className="icon">🏭</div>No internal sales in this period</div>
              ) : (
                Object.entries(intByDest).map(([destName, group]) => (
                  <div key={destName} className="card" style={{ padding: 0, overflow: 'hidden', marginBottom: 20 }}>
                    <div style={{ padding: '12px 16px', background: 'var(--bg2)', borderBottom: '1px solid var(--border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <div style={{ fontWeight: 700, fontSize: 15 }}>🏭 {destName}</div>
                      <div style={{ fontFamily: 'var(--mono)', color: 'var(--accent)', fontWeight: 700 }}>{fmt(group.total)}</div>
                    </div>
                    <table>
                      <thead><tr><th>Product</th><th>Barcode</th><th>MRP</th><th>Qty</th><th>Total Value</th></tr></thead>
                      <tbody>
                        {group.items.map((item, i) => (
                          <tr key={i}>
                            <td style={{ fontWeight: 600, color: 'var(--text)' }}>{item.product_name}</td>
                            <td><span style={{ fontFamily: 'var(--mono)', fontSize: 12 }}>{item.product_barcode}</span></td>
                            <td style={{ fontFamily: 'var(--mono)' }}>{fmt(item.mrp)}</td>
                            <td><span className="badge badge-purple">{item.quantity}</span></td>
                            <td style={{ fontWeight: 700, color: 'var(--accent)', fontFamily: 'var(--mono)' }}>{fmt(item.total_amount)}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                ))
              )}
            </>
          )}
        </>
      )}

      {showPrintModal && (
        <PrintModal
          onClose={() => setShowPrintModal(false)}
          onPrint={handlePrint}
        />
      )}
    </div>
  );
}
